<template>
  <view class="page-container">

    <!-- 筛选栏 -->
    <view class="filter-box">
      <u-dropdown>
        <u-dropdown-item v-model="filterTarget" :options="targetOptions" @change="onFilterChange"></u-dropdown-item>
        <u-dropdown-item v-model="filterRegion" :options="regionOptions" @change="onFilterChange"></u-dropdown-item>
        <u-dropdown-item v-model="filterOrgType" :options="orgTypeOptions" @change="onFilterChange"></u-dropdown-item>
      </u-dropdown>
    </view>

    <!-- 搜索栏 -->
    <view class="search-box">
      <u-search
        v-model="keyword"
        placeholder="搜索心理咨询机构"
        shape="round"
        @search="onSearch"
        @clear="onSearch"
      ></u-search>
    </view>

    <!-- 加载状态 -->
    <view v-if="loading" class="loading-state">
      <u-loading-icon mode="circle"></u-loading-icon>
      <text class="loading-text">加载中...</text>
    </view>

    <view v-else class="content-box">

      <!-- 咨询机构名录 -->
      <view class="section mt-4">
        <text class="section-title">心理咨询机构</text>
        <u-cell-group>
          <u-cell
            v-for="org in organizations"
            :key="org.id"
            :title="org.name"
            :label="`${org.typeName} · ${org.contact}`"
            is-link
            @click="contactOrg(org)"
          >
            <template #value>
              <u-tag v-if="org.isFree" text="免费" type="success" size="mini"></u-tag>
            </template>
          </u-cell>
        </u-cell-group>

        <!-- 机构加载更多 -->
        <u-loadmore 
          :status="orgLoadStatus" 
          @loadmore="onOrgPageChange"
          v-if="organizations.length > 0"
        />

        <!-- 机构空状态 -->
        <u-empty v-if="organizations.length === 0" mode="data" description="暂无心理咨询机构"></u-empty>
      </view>
    </view>
  </view>
</template>

<script setup lang="ts">
import { ref, onMounted } from 'vue'
import request from '@/utils/request'

// 筛选条件
const filterTarget = ref('all')
const filterRegion = ref('all')
const filterOrgType = ref('all')
const keyword = ref('')



// 机构分页
const orgPage = ref(1)
const orgPageSize = ref(10)
const orgTotal = ref(0)
const orgLoadStatus = ref<'loading' | 'loadmore' | 'nomore'>('loadmore')

// 筛选项
const targetOptions = ref<{ text: string; value: string }[]>([])
const regionOptions = ref<{ text: string; value: string }[]>([])
const orgTypeOptions = ref<{ text: string; value: string }[]>([])

// 列表数据
const organizations = ref<any[]>([])
const loading = ref(false)

// 获取目标人群选项
const fetchTargetOptions = async () => {
  try {
    const res = await request.get('/api/resource/rehab/psychological/guides/targets')
    const data = res.data || res.data || {}
    if (data.targets && Array.isArray(data.targets)) {
      targetOptions.value = [
        { text: '全部人群', value: 'all' },
        ...data.targets.map((item: any) => ({
          text: item.text || item.name,
          value: item.value || item.code
        }))
      ]
    }
  } catch (error) {
    targetOptions.value = [{ text: '全部人群', value: 'all' }]
  }
}

// 获取地区选项
const fetchRegionOptions = async () => {
  try {
    const res = await request.get('/api/resource/rehab/psychological/organizations/regions')
    const data = res.data || res.data || {}
    if (data.regions && Array.isArray(data.regions)) {
      regionOptions.value = [
        { text: '全部地区', value: 'all' },
        ...data.regions.map((item: any) => ({
          text: item.text || item.name,
          value: item.value || item.code
        }))
      ]
    }
  } catch (error) {
    regionOptions.value = [{ text: '全部地区', value: 'all' }]
  }
}

// 获取机构类型选项
const fetchOrgTypeOptions = async () => {
  try {
    const res = await request.get('/api/resource/rehab/psychological/organizations/types')
    const data = res.data || res.data || {}
    if (data.types && Array.isArray(data.types)) {
      orgTypeOptions.value = [
        { text: '全部类型', value: 'all' },
        ...data.types.map((item: any) => ({
          text: item.text || item.name,
          value: item.value || item.code
        }))
      ]
    }
  } catch (error) {
    orgTypeOptions.value = [{ text: '全部类型', value: 'all' }]
  }
}


// 获取心理咨询机构列表
const fetchOrganizations = async (isRefresh = false) => {
  if (isRefresh) {
    orgPage.value = 1
    organizations.value = []
    orgLoadStatus.value = 'loading'
  }
  
  if (orgLoadStatus.value === 'nomore' && !isRefresh) return

  try {
    const params: Record<string, any> = {
      page: orgPage.value,
      pageSize: orgPageSize.value
    }
    if (filterRegion.value !== 'all') params.region = filterRegion.value
    if (filterOrgType.value !== 'all') params.type = filterOrgType.value
    if (keyword.value) params.keyword = keyword.value

    const res = await request.get('/api/resource/rehab/psychological/orgs', { params })
    const responseData = res.data || res.data || {}
    const records = responseData.list || []
    
    organizations.value.push(...records)
    orgTotal.value = responseData.total || 0
    
    if (records.length < orgPageSize.value) {
      orgLoadStatus.value = 'nomore'
    } else {
      orgLoadStatus.value = 'loadmore'
      orgPage.value++
    }
  } catch (error) {
    uni.__f__('error','at pages/resource/rehab/PsychologicalSupport.vue:182','获取机构列表失败:', error)
    uni.showToast({ title: '机构加载失败', icon: 'none' })
    orgLoadStatus.value = 'loadmore'
  }
}



// 机构分页变化
const onOrgPageChange = () => {
  fetchOrganizations()
}

// 搜索
const onSearch = () => {
  fetchOrganizations(true)
}

// 筛选变化
const onFilterChange = () => {
  fetchOrganizations(true)
}


// 联系机构
const contactOrg = (org: any) => {
  if (!org?.id) {
    uni.showToast({ title: '机构信息不完整', icon: 'none' })
    return
  }
  uni.navigateTo({
    url: `/pages/resource/rehab/OrganizationDetail?id=${org.id}`
  })
}

onMounted(() => {
  fetchTargetOptions()
  fetchRegionOptions()
  fetchOrgTypeOptions()
  fetchOrganizations()
})
</script>

